insert into sentences (id, course_id, hanzi, pinyin, english, difficulty, grammar_notes) values
  ('s-1', 'course-mandarin-1', '你好！', 'Nǐ hǎo!', 'Hello!', 1, null),
  ('s-2', 'course-mandarin-1', '再见！', 'Zàijiàn!', 'Goodbye!', 1, null),
  ('s-3', 'course-mandarin-1', '我叫小明。', 'Wǒ jiào Xiǎomíng.', 'My name is Xiaoming.', 1, '叫 + name introduces yourself'),
  ('s-4', 'course-mandarin-1', '我是学生。', 'Wǒ shì xuéshēng.', 'I am a student.', 1, 'Subject + 是 + noun'),
  ('s-5', 'course-mandarin-1', '你是中国人吗？', 'Nǐ shì Zhōngguórén ma?', 'Are you Chinese?', 2, 'Add 吗 for yes/no questions'),
  ('s-6', 'course-mandarin-1', '我来自美国。', 'Wǒ láizì Měiguó.', 'I come from the United States.', 2, '来自 + place'),
  ('s-7', 'course-mandarin-1', '她是谁？', 'Tā shì shéi?', 'Who is she?', 2, null),
  ('s-8', 'course-mandarin-1', '你几岁？', 'Nǐ jǐ suì?', 'How old are you?', 2, '几 + 岁 for age'),
  ('s-9', 'course-mandarin-1', '我有一个哥哥。', 'Wǒ yǒu yī gè gēge.', 'I have an older brother.', 2, '有 means to have; 个 is a measure word'),
  ('s-10', 'course-mandarin-1', '我的妈妈很好。', 'Wǒ de māma hěn hǎo.', 'My mom is very good.', 2, '的 marks possession'),
  ('s-11', 'course-mandarin-1', '我妈妈是医生。', 'Wǒ māma shì yīshēng.', 'My mom is a doctor.', 2, null),
  ('s-12', 'course-mandarin-1', '现在几点？', 'Xiànzài jǐ diǎn?', 'What time is it now?', 2, null),
  ('s-13', 'course-mandarin-1', '今天星期一。', 'Jīntiān xīngqī yī.', 'Today is Monday.', 2, null),
  ('s-14', 'course-mandarin-1', '我七点起床。', 'Wǒ qī diǎn qǐchuáng.', 'I get up at seven o''clock.', 2, null),
  ('s-15', 'course-mandarin-1', '我喜欢喝茶。', 'Wǒ xǐhuān hē chá.', 'I like to drink tea.', 2, null),
  ('s-16', 'course-mandarin-1', '请给我米饭。', 'Qǐng gěi wǒ mǐfàn.', 'Please give me rice.', 2, null),
  ('s-17', 'course-mandarin-1', '我饿了，想吃饭。', 'Wǒ è le, xiǎng chī fàn.', 'I''m hungry and want to eat.', 2, null),
  ('s-18', 'course-mandarin-1', '这个多少钱？', 'Zhège duōshao qián?', 'How much is this?', 2, null),
  ('s-19', 'course-mandarin-1', '太贵了！', 'Tài guì le!', 'Too expensive!', 2, null),
  ('s-20', 'course-mandarin-1', '我的家很大。', 'Wǒ de jiā hěn dà.', 'My home is very big.', 2, null),
  ('s-21', 'course-mandarin-1', '手机在哪里？', 'Shǒujī zài nǎlǐ?', 'Where is the phone?', 2, '在 + location'),
  ('s-22', 'course-mandarin-1', '今天天气很冷。', 'Jīntiān tiānqì hěn lěng.', 'The weather is very cold today.', 2, null),
  ('s-23', 'course-mandarin-1', '你怎么去？', 'Nǐ zěnme qù?', 'How do you get there?', 2, null),
  ('s-24', 'course-mandarin-1', '谢谢！不客气。', 'Xièxie! Bù kèqi.', 'Thank you! You''re welcome.', 1, null);
